import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreService', () {
    test('dispose cancels without sending a playback update', () {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(controller.dispose);

      var notifications = 0;
      service.addListener(() => notifications++);

      service.dispose();

      expect(notifications, 0);
    });

    test('ignores one-shot corrections during continuous user interaction',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);

      controller.updateZoom(2.0);
      service.onUserCorrection();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.onUserInteractionEnd();

      expect(service.pausedByUserCorrection, isFalse);
    });

    test('toggle resumes from temporary user yield instead of pausing',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.toggle();

      expect(service.isExploring, isTrue);
      expect(service.isPaused, isFalse);
      expect(service.pausedByUserCorrection, isFalse);
    });

    test('resume replans from a zoom changed while paused', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.pause();

      controller.updateZoom(10.0);
      service.resume();

      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 1200.0);
    });

    test('ignores unmatched continuous interaction end callbacks', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 120.0);

      service.onUserInteractionEnd();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, AutoExploreConfig.defaultMinZoom);
    });
  });
}

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

/// Replayable viewport dimensions for CPU coordinate mapping.
///
/// Render requests should provide positive dimensions. When a direct mapping
/// caller passes invalid dimensions, fall back to a square viewport instead of
/// leaking zero/negative aspect ratios into fractal coordinates.
final class CpuViewportDimensions {
  const CpuViewportDimensions({required this.width, required this.height});

  final int width;
  final int height;

  factory CpuViewportDimensions.fromSize({
    required int width,
    required int height,
  }) {
    if (width <= 0 || height <= 0) {
      return const CpuViewportDimensions(width: 1, height: 1);
    }
    return CpuViewportDimensions(width: width, height: height);
  }

  double get aspect => width / height;
}

/// Explicit dimensions contract for CPU render work.
final class CpuRenderDimensions {
  const CpuRenderDimensions({required this.width, required this.height});

  final int width;
  final int height;

  void validate() {
    if (width <= 0 || height <= 0) {
      throw ArgumentError.value(
        (width, height),
        'full viewport',
        'must be positive',
      );
    }
  }
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Explicit point contract for a CPU pixel sample inside a full viewport.
final class CpuRenderSamplePoint {
  const CpuRenderSamplePoint({
    required this.fullWidth,
    required this.fullHeight,
    required this.x,
    required this.y,
  });

  final int fullWidth;
  final int fullHeight;
  final int x;
  final int y;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (x < 0 || y < 0 || x >= fullWidth || y >= fullHeight) {
      throw ArgumentError.value(
        (x, y),
        'sample coordinate',
        'must be inside the full viewport',
      );
    }
  }
}

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = panX,
        centerY = panY,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = CpuViewportDimensions.fromSize(
          width: width,
          height: height,
        ).aspect;

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

/// Replayable CPU anti-aliasing grid derived from a requested sample count.
///
/// The CPU renderer samples a square grid, so non-square requests are rounded up
/// to the next square grid instead of silently dropping requested samples.
final class CpuSampleGrid {
  CpuSampleGrid.fromRequestedCount(int requestedCount)
      : this._(
          requestedCount: requestedCount,
          samplesPerAxis: _samplesPerAxisFor(requestedCount),
        );

  const CpuSampleGrid._({
    required this.requestedCount,
    required this.samplesPerAxis,
  });

  final int requestedCount;
  final int samplesPerAxis;

  int get totalSamples => samplesPerAxis * samplesPerAxis;

  bool get wasRoundedUp => totalSamples > math.max(1, requestedCount);

  static int _samplesPerAxisFor(int requestedCount) {
    if (requestedCount <= 0) return 1;
    return math.max(1, math.sqrt(requestedCount).ceil());
  }
}

import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    final rp = ReceivePort();
    _sendPort.send((req, rp.sendPort));
    try {
      final msg = await rp.first;
      if (msg is CpuTileRenderResponse) return msg;
      if (msg is _CpuTileRenderFailure) throw msg.toException();
      throw StateError('Unexpected CPU tile worker reply: ${msg.runtimeType}');
    } finally {
      rp.close();
    }
  }

  void dispose() {
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }
}

/// Exception surfaced when the worker isolate could not render a requested tile.
class CpuTileWorkerException implements Exception {
  const CpuTileWorkerException({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  @override
  String toString() => 'CpuTileWorkerException($errorType): $message';
}

final class _CpuTileRenderFailure {
  const _CpuTileRenderFailure({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  factory _CpuTileRenderFailure.from(Object error, StackTrace stackTrace) {
    return _CpuTileRenderFailure(
      errorType: error.runtimeType.toString(),
      message: error.toString(),
      stackTraceText: stackTrace.toString(),
    );
  }

  CpuTileWorkerException toException() {
    return CpuTileWorkerException(
      errorType: errorType,
      message: message,
      stackTraceText: stackTraceText,
    );
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    SendPort? replyTo;
    try {
      final (CpuTileRenderRequest req, SendPort port) =
          msg as (CpuTileRenderRequest, SendPort);
      replyTo = port;
      final resp = renderCpuTileInIsolate(req);
      replyTo.send(resp);
    } catch (error, stackTrace) {
      replyTo?.send(_CpuTileRenderFailure.from(error, stackTrace));
    }
  });
}

