import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';

void main() {
  group('CPU refinement patch pack', () {
    test('critical formulas are native (not synthetic fallback)', () {
      expect(hasNativeCpuFormula('phoenix'), isTrue);
      expect(hasNativeCpuFormula('multibrot4'), isTrue);
      expect(hasNativeCpuFormula('multibrot5'), isTrue);
    });

    test('module-aware CPU defaults are stable', () {
      expect(cpuControlScalarForModule('nova', const {}), 1.0);
      expect(
          cpuControlScalarForModule('nova', const {'relaxation': 1.75}), 1.75);
      expect(cpuControlScalarForModule('mandelbrot', const {}), 4.0);

      final phoenixDefault = cpuJuliaCForModule('phoenix', const {});
      expect(phoenixDefault.x, closeTo(0.5667, 1e-6));
      expect(phoenixDefault.y, closeTo(0.0, 1e-6));

      final phoenixCustom = cpuJuliaCForModule('phoenix', const {
        'phoenixCReal': 0.2,
        'phoenixCImag': -0.3,
      });
      expect(phoenixCustom.x, closeTo(0.2, 1e-6));
      expect(phoenixCustom.y, closeTo(-0.3, 1e-6));
    });

    test('multibrot4/5 and phoenix are visually differentiated', () async {
      const width = 56;
      const height = 56;
      const iterations = 96;
      const bailout = 4.0;
      final viewPan = Vector2(-0.5, 0.0);
      const viewZoom = 1.1;
      final juliaC = Vector2(0.5667, 0.0);

      final mandelbrot = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: viewPan,
        viewZoom: viewZoom,
        iterations: iterations,
        bailout: bailout,
        juliaC: juliaC,
        width: width,
        height: height,
        sampleCount: 1,
      );

      final multibrot4 = await renderCpuFrame(
        moduleId: 'multibrot4',
        viewPan: viewPan,
        viewZoom: viewZoom,
        iterations: iterations,
        bailout: bailout,
        juliaC: juliaC,
        width: width,
        height: height,
        sampleCount: 1,
      );

      final multibrot5 = await renderCpuFrame(
        moduleId: 'multibrot5',
        viewPan: viewPan,
        viewZoom: viewZoom,
        iterations: iterations,
        bailout: bailout,
        juliaC: juliaC,
        width: width,
        height: height,
        sampleCount: 1,
      );

      final phoenix = await renderCpuFrame(
        moduleId: 'phoenix',
        viewPan: Vector2(0.0, 0.0),
        viewZoom: 1.2,
        iterations: iterations,
        bailout: bailout,
        juliaC: juliaC,
        width: width,
        height: height,
        sampleCount: 1,
      );

      double diffRatio(CpuRenderFrame a, CpuRenderFrame b) {
        int diff = 0;
        final total = a.width * a.height;
        for (int i = 0; i < a.rgba.length; i += 4) {
          final dr = (a.rgba[i] - b.rgba[i]).abs();
          final dg = (a.rgba[i + 1] - b.rgba[i + 1]).abs();
          final db = (a.rgba[i + 2] - b.rgba[i + 2]).abs();
          if (dr + dg + db >= 14) diff++;
        }
        return diff / total;
      }

      expect(diffRatio(multibrot4, mandelbrot), greaterThan(0.08));
      expect(diffRatio(multibrot5, mandelbrot), greaterThan(0.08));
      expect(diffRatio(multibrot4, multibrot5), greaterThan(0.04));
      expect(diffRatio(phoenix, mandelbrot), greaterThan(0.08));
    });
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';

void main() {
  group('CPU Formula Registry', () {
    test('resolves every escape-time catalog module id', () {
      final unresolved = <String>[];
      for (final cfg in escapeTimeCatalog) {
        final formula = cpuFormulaForModuleId(cfg.id);
        final color = formula(0.0, 0.0, 32, 4.0, Vector2.zero());
        final valid =
            color.$1.isFinite && color.$2.isFinite && color.$3.isFinite;
        if (!valid) {
          unresolved.add(cfg.id);
        }
      }
      expect(
        unresolved,
        isEmpty,
        reason:
            'CPU formula resolver produced invalid output for: ${unresolved.join(', ')}',
      );
    });

    test('non-mandelbrot formulas differ from Mandelbrot baseline', () async {
      const width = 64;
      const height = 64;

      // One standard view for consistent comparisons.
      final viewPan = Vector2(-0.5, 0.0);
      const viewZoom = 3.0;
      const iterations = 80;
      const bailout = 4.0;
      final juliaC = Vector2(-0.8, 0.156);

      final baseline = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: viewPan,
        viewZoom: viewZoom,
        iterations: iterations,
        bailout: bailout,
        juliaC: juliaC,
        width: width,
        height: height,
        sampleCount: 1,
      );

      for (final cfg in escapeTimeCatalog) {
        if (cfg.id == 'mandelbrot') continue;

        final frame = await renderCpuFrame(
          moduleId: cfg.id,
          viewPan: viewPan,
          viewZoom: viewZoom,
          iterations: iterations,
          bailout: bailout,
          juliaC: juliaC,
          width: width,
          height: height,
          sampleCount: 1,
        );

        int diff = 0;
        final total = width * height;
        for (int i = 0; i < frame.rgba.length; i += 4) {
          final dr = (frame.rgba[i] - baseline.rgba[i]).abs();
          final dg = (frame.rgba[i + 1] - baseline.rgba[i + 1]).abs();
          final db = (frame.rgba[i + 2] - baseline.rgba[i + 2]).abs();
          if (dr + dg + db >= 10) diff++;
        }

        final ratio = diff / total;
        expect(
          ratio,
          greaterThan(0.05),
          reason:
              'CPU formula for ${cfg.id} is too similar to Mandelbrot baseline (diffRatio=${ratio.toStringAsFixed(3)}).',
        );
      }
    }, timeout: const Timeout(Duration(minutes: 2)));

    test('renders non-black ratio above 1%', () async {
      const width = 64;
      const height = 64;

      final viewPan = Vector2(-0.5, 0.0);
      const viewZoom = 3.0;
      const iterations = 80;
      const bailout = 4.0;
      final juliaC = Vector2(-0.8, 0.156);

      for (final cfg in escapeTimeCatalog) {
        final frame = await renderCpuFrame(
          moduleId: cfg.id,
          viewPan: viewPan,
          viewZoom: viewZoom,
          iterations: iterations,
          bailout: bailout,
          juliaC: juliaC,
          width: width,
          height: height,
          sampleCount: 1,
        );

        int nonBlack = 0;
        for (int i = 0; i < frame.rgba.length; i += 4) {
          if (frame.rgba[i] > 8 ||
              frame.rgba[i + 1] > 8 ||
              frame.rgba[i + 2] > 8) {
            nonBlack++;
          }
        }
        final ratio = nonBlack / (width * height);
        expect(
          ratio,
          greaterThan(0.01),
          reason:
              '${cfg.id} produced too many black pixels (nonBlackRatio=${ratio.toStringAsFixed(3)}).',
        );
      }
    }, timeout: const Timeout(Duration(minutes: 2)));
  });
}

